class Solution {
    public int minChanges(int[] nums, int k) {
        int n = nums.length;
        int[] prefixXor = new int[n + 1];
        for (int i = 0; i < n; i++) {
            prefixXor[i + 1] = prefixXor[i] ^ nums[i];
        }
        int ans = Integer.MAX_VALUE;
        for (int i = 0; i <= n - k; i++) {
            int xor = prefixXor[i + k] ^ prefixXor[i];
            int count = 0;
            for (int j = i; j < i + k; j++) {
                count += (xor ^ nums[j]) > 0 ? 1 : 0;
            }
            ans = Math.min(ans, count);
        }
        return ans;
    }
}
